INSERT OR REPLACE INTO research_questionnaires
     (id, study_id, slug, title, description, schema_json,
      position, status, version, created_at, updated_at)
     VALUES (
       '00000000-0000-4000-8000-100000000010',
       '00000000-0000-4000-8000-100000000001',
       't1-pre-game',
       'T1 — Pre game',
       'Questionario iniziale, da compilare prima della sessione di gioco.',
       '{"title":"Questionario T1 — Pre-Game","description":"Questo questionario raccoglie le tue risposte prima dell''attivita'' di gioco. Rispondi in modo spontaneo: non ci sono risposte giuste o sbagliate. I tuoi dati sono completamente anonimi.","showProgressBar":"top","progressBarType":"pages","showQuestionNumbers":"off","requiredText":"*","locale":"it","pages":[{"name":"codice_anonimo","title":"Codice Anonimo","description":"Per collegare le tue risposte ai questionari successivi senza identificarti, crea un codice personale rispondendo alle 4 domande. Ricorda le risposte che dai: ti serviranno per rigenerare lo stesso codice nei prossimi questionari.","elements":[{"type":"text","name":"anon_madre","title":"Prima lettera del nome di tua madre","description":"Esempio: se tua madre si chiama Maria, scrivi M","isRequired":true,"maxLength":1,"inputType":"text","validators":[{"type":"regex","regexp":"^[a-zA-Z\\u00C0-\\u017F]$","text":"Inserisci una sola lettera dell''alfabeto"}]},{"type":"text","name":"anon_giorno","title":"Giorno del tuo compleanno (1-31)","description":"Solo il giorno. Esempio: se sei nato/a il 15 marzo, scrivi 15","isRequired":true,"inputType":"number","min":1,"max":31,"validators":[{"type":"regex","regexp":"^([1-9]|[12][0-9]|3[01])$","text":"Inserisci un numero da 1 a 31"}]},{"type":"text","name":"anon_nome","title":"Prima lettera del tuo nome","description":"Esempio: se ti chiami Vittorio, scrivi V","isRequired":true,"maxLength":1,"inputType":"text","validators":[{"type":"regex","regexp":"^[a-zA-Z\\u00C0-\\u017F]$","text":"Inserisci una sola lettera dell''alfabeto"}]},{"type":"text","name":"anon_telefono","title":"Prime due cifre del tuo numero di telefono","description":"Esempio: se il tuo numero inizia con 34..., scrivi 34","isRequired":true,"inputType":"number","min":0,"max":99,"validators":[{"type":"regex","regexp":"^[0-9]{1,2}$","text":"Inserisci due cifre (00-99)"}]}]},{"name":"tipi","title":"Personalita''","description":"Leggi le seguenti caratteristiche e indica quanto ti senti descritto da ogni coppia di aggettivi.","elements":[{"type":"matrix","name":"ITIPI","title":"Mi vedo come una persona...","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Leggermente in disaccordo"},{"value":4,"text":"Ne'' d''accordo ne'' in disaccordo"},{"value":5,"text":"Leggermente d''accordo"},{"value":6,"text":"D''accordo"},{"value":7,"text":"Fortemente d''accordo"}],"rows":[{"value":"TIPI_01","text":"Estroversa, esuberante"},{"value":"TIPI_02","text":"Difficile, polemica"},{"value":"TIPI_03","text":"Affidabile, autodisciplinata"},{"value":"TIPI_04","text":"Preoccupata, che si agita facilmente"},{"value":"TIPI_05","text":"Aperta a nuove esperienze, con molti interessi"},{"value":"TIPI_06","text":"Riservata, silenziosa"},{"value":"TIPI_07","text":"Comprensiva, affettuosa"},{"value":"TIPI_08","text":"Disorganizzata, distratta"},{"value":"TIPI_09","text":"Calma, emotivamente stabile"},{"value":"TIPI_10","text":"Tradizionalista, abitudinaria"}]}]},{"name":"mdmq","title":"Stile Decisionale","description":"Indica quanto ciascuna affermazione descrive il tuo modo abituale di prendere decisioni.","elements":[{"type":"matrix","name":"MDMQ","columns":[{"value":0,"text":"Non vero per me"},{"value":1,"text":"Abbastanza vero per me"},{"value":2,"text":"Vero per me"}],"rows":[{"value":"MDMQ_01","text":"Mi sento sotto un''enorme pressione di tempo quando prendo decisioni."},{"value":"MDMQ_02","text":"Mi piace prendere in considerazione tutte le alternative."},{"value":"MDMQ_03","text":"Preferisco lasciare le decisioni agli altri."},{"value":"MDMQ_04","text":"Cerco di individuare gli svantaggi di tutte le alternative."},{"value":"MDMQ_05","text":"Perdo molto tempo su questioni banali prima di arrivare alla decisione finale."},{"value":"MDMQ_06","text":"Considero quale sia il modo migliore per mettere in atto una decisione."},{"value":"MDMQ_07","text":"Anche dopo aver preso una decisione, rimando il momento di metterla in pratica."},{"value":"MDMQ_08","text":"Quando prendo decisioni mi piace raccogliere molte informazioni."},{"value":"MDMQ_09","text":"Evito di prendere decisioni."},{"value":"MDMQ_10","text":"Quando devo prendere una decisione, aspetto a lungo prima di iniziare a pensarci."},{"value":"MDMQ_11","text":"Non mi piace assumermi la responsabilita'' di prendere decisioni."},{"value":"MDMQ_12","text":"Cerco di avere chiari i miei obiettivi prima di scegliere."},{"value":"MDMQ_13","text":"La possibilita'' che un piccolo dettaglio possa andare storto mi fa cambiare improvvisamente preferenza."},{"value":"MDMQ_14","text":"Se una decisione puo'' essere presa da me o da un''altra persona, lascio che la prenda l''altra persona."},{"value":"MDMQ_15","text":"Quando affronto una decisione difficile mi sento pessimista riguardo alla possibilita'' di trovare una buona soluzione."},{"value":"MDMQ_16","text":"Faccio molta attenzione prima di scegliere."},{"value":"MDMQ_17","text":"Non prendo decisioni a meno che non sia davvero necessario."},{"value":"MDMQ_18","text":"Rimando le decisioni finche'' non e'' troppo tardi."},{"value":"MDMQ_19","text":"Preferisco che a decidere per me siano persone meglio informate."},{"value":"MDMQ_20","text":"Dopo aver preso una decisione, passo molto tempo a convincermi che fosse quella giusta."},{"value":"MDMQ_21","text":"Rimando il momento di prendere decisioni."},{"value":"MDMQ_22","text":"Non riesco a ragionare lucidamente se devo prendere una decisione in fretta."}]}]},{"name":"roci","title":"Gestione del Conflitto","description":"Pensa a come gestisci le situazioni di conflitto con i tuoi colleghi sul lavoro.","elements":[{"type":"matrix","name":"ROCI","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Indeciso"},{"value":4,"text":"D''accordo"},{"value":5,"text":"Fortemente d''accordo"}],"rows":[{"value":"ROCI_01","text":"Cerco di esaminare a fondo un problema con il mio collega per trovare una soluzione accettabile per entrambi."},{"value":"ROCI_02","text":"In generale cerco di soddisfare i bisogni del mio collega."},{"value":"ROCI_03","text":"Cerco di evitare di essere messo in difficolta'' e tengo per me il conflitto con il mio collega."},{"value":"ROCI_04","text":"Cerco di integrare le mie idee con quelle del mio collega per arrivare a una decisione congiunta."},{"value":"ROCI_05","text":"Do qualcosa per ottenere qualcosa in cambio."},{"value":"ROCI_06","text":"Cerco di lavorare con il mio collega per trovare soluzioni che soddisfino le aspettative di entrambi."},{"value":"ROCI_07","text":"Di solito evito discussioni aperte sulle mie divergenze con il mio collega."},{"value":"ROCI_08","text":"Di solito resto fermo sulla mia soluzione a un problema."},{"value":"ROCI_09","text":"Cerco di trovare una via di mezzo per risolvere un''impasse."},{"value":"ROCI_10","text":"Uso la mia influenza per far accettare le mie idee."},{"value":"ROCI_11","text":"Uso la mia autorita'' per prendere una decisione a mio favore."},{"value":"ROCI_12","text":"Di solito cerco di andare incontro ai desideri del mio collega."},{"value":"ROCI_13","text":"Cedo di fronte ai desideri del mio collega."},{"value":"ROCI_14","text":"A volte vinco e a volte perdo."},{"value":"ROCI_15","text":"Scambio informazioni accurate con il mio collega per risolvere un problema insieme."},{"value":"ROCI_16","text":"A volte aiuto il mio collega a prendere una decisione a suo favore."},{"value":"ROCI_17","text":"Di solito faccio concessioni al mio collega."},{"value":"ROCI_18","text":"Argomento il mio caso con il collega per mostrare i meriti della mia posizione."},{"value":"ROCI_19","text":"Cerco di minimizzare le nostre differenze per raggiungere un compromesso."},{"value":"ROCI_20","text":"Di solito propongo una soluzione intermedia per sbloccare una situazione."},{"value":"ROCI_21","text":"Negozio con il mio collega in modo da raggiungere un compromesso."},{"value":"ROCI_22","text":"Cerco di stare lontano dai disaccordi con il mio collega."},{"value":"ROCI_23","text":"Evito un confronto con il mio collega."},{"value":"ROCI_24","text":"Uso la mia competenza per prendere una decisione a mio favore."},{"value":"ROCI_25","text":"Spesso assecondo i suggerimenti del mio collega."},{"value":"ROCI_26","text":"Uso il dare e avere in modo da raggiungere un compromesso."},{"value":"ROCI_27","text":"Sono generalmente fermo nel perseguire la mia posizione."},{"value":"ROCI_28","text":"Cerco di portare alla luce tutte le nostre preoccupazioni affinche'' le questioni possano essere risolte nel modo migliore."}]}]},{"name":"svo","title":"Orientamento Sociale","description":"Leggi attentamente le istruzioni prima di rispondere.","elements":[{"type":"html","name":"svo_intro","html":"<div style=''background:#FFFFFF;padding:18px 22px;border-radius:10px;margin:4px 0 16px;box-shadow:0 1px 4px rgba(0,0,0,.06);''><p style=''margin:0 0 10px;color:#1b2528;font-weight:600;''>Immagina di essere stato/a accoppiato/a casualmente con <u>un''altra persona</u> che non conosci e che non incontrerai mai.</p><p style=''margin:0 0 10px;color:#657179;font-size:.95em;line-height:1.5;''>L''altra persona non sa chi sei, come tu non sai chi sia. Anche le vostre scelte resteranno reciprocamente anonime.</p><p style=''margin:0 0 10px;color:#657179;font-size:.95em;line-height:1.5;''>Ti presenteremo 6 scelte. In ciascuna dovrai decidere come distribuire dei punti (che valgono soldi) tra te stesso/a e l''altra persona. Ogni punto ha lo stesso valore per te e per l''altra persona.</p><p style=''margin:0;color:#657179;font-size:.95em;line-height:1.5;''>Per ciascuna scelta vedrai 9 combinazioni possibili. La riga sopra indica quanti punti riceveresti tu; quella sotto quanti ne riceverebbe l''altra persona. <strong>Clicca sulla combinazione che preferisci.</strong></p></div>"},{"type":"html","name":"svo_widget","html":"<div id=''svoContainer''></div>"}]},{"name":"tps","title":"Sicurezza Psicologica nel Team","description":"Pensa al team con cui lavori abitualmente. Indica il tuo grado di accordo con ciascuna affermazione.","elements":[{"type":"matrix","name":"TPS","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Leggermente in disaccordo"},{"value":4,"text":"Neutrale"},{"value":5,"text":"Leggermente d''accordo"},{"value":6,"text":"D''accordo"},{"value":7,"text":"Fortemente d''accordo"}],"rows":[{"value":"TPS_01","text":"Se commetti un errore in questo team, viene usato contro di te."},{"value":"TPS_02","text":"I membri di questo team sono in grado di sollevare problemi e questioni difficili."},{"value":"TPS_03","text":"Le persone in questo team a volte rifiutano gli altri perche'' sono diversi."},{"value":"TPS_04","text":"E'' sicuro correre rischi in questo team."},{"value":"TPS_05","text":"E'' difficile chiedere aiuto agli altri membri di questo team."},{"value":"TPS_06","text":"Nessuno in questo team saboterebbe deliberatamente il mio lavoro."},{"value":"TPS_07","text":"Le mie competenze e i miei talenti unici sono apprezzati e utilizzati in questo team."}]}]},{"name":"tci","title":"Clima di Team","description":"Pensa al team di lavoro con cui collabori abitualmente.","elements":[{"type":"matrix","name":"TCI","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Indeciso"},{"value":4,"text":"D''accordo"},{"value":5,"text":"Fortemente d''accordo"}],"rows":[{"value":"TCI_01","text":"In che misura sei d''accordo con gli obiettivi del tuo team?"},{"value":"TCI_02","text":"In che misura ritieni che gli obiettivi del team siano compresi chiaramente dagli altri membri?"},{"value":"TCI_03","text":"In che misura ritieni che gli obiettivi del team siano effettivamente raggiungibili?"},{"value":"TCI_04","text":"Quanto ritieni che questi obiettivi siano importanti per l''organizzazione?"},{"value":"TCI_05","text":"Abbiamo un atteggiamento del tipo ''siamo tutti nella stessa barca''."},{"value":"TCI_06","text":"Le persone si tengono reciprocamente informate sulle questioni lavorative nel team."},{"value":"TCI_07","text":"Le persone si sentono comprese e accettate reciprocamente."},{"value":"TCI_08","text":"Ci sono tentativi concreti di condividere le informazioni in tutto il team."},{"value":"TCI_09","text":"I membri del team sono pronti a mettere in discussione le basi di cio'' che il team sta facendo?"},{"value":"TCI_10","text":"Il team valuta criticamente i potenziali punti deboli di cio'' che sta facendo?"},{"value":"TCI_11","text":"I membri del team costruiscono sulle idee degli altri per ottenere i migliori risultati?"},{"value":"TCI_12","text":"Le persone in questo team sono sempre alla ricerca di modi nuovi e originali per affrontare i problemi."},{"value":"TCI_13","text":"In questo team ci prendiamo il tempo necessario per sviluppare nuove idee."},{"value":"TCI_14","text":"Le persone nel team cooperano per contribuire a sviluppare e applicare nuove idee."}]}]},{"name":"secom","title":"Autoefficacia Comunicativa","description":"Pensa alle tue capacita'' di comunicazione nel lavoro di squadra. Indica quanto ti senti sicuro/a in ciascuna delle seguenti situazioni.","elements":[{"type":"matrix","name":"SECOM","columns":[{"value":1,"text":"Per niente sicuro/a"},{"value":2,"text":"2"},{"value":3,"text":"3"},{"value":4,"text":"4"},{"value":5,"text":"5"},{"value":6,"text":"6"},{"value":7,"text":"Completamente sicuro/a"}],"rows":[{"value":"SECOM_01","text":"Sono in grado di esprimere le mie idee in modo chiaro durante una discussione di gruppo."},{"value":"SECOM_02","text":"Sono in grado di ascoltare attivamente i miei colleghi e cogliere i punti chiave del loro ragionamento."},{"value":"SECOM_03","text":"Sono in grado di gestire un disaccordo con un collega senza compromettere la relazione."},{"value":"SECOM_04","text":"Sono in grado di coordinare le attivita'' del mio team comunicando in modo efficace."}]}]}]}',
       0,
       'active',
       1,
       unixepoch()*1000,
       unixepoch()*1000
     );

INSERT OR REPLACE INTO research_questionnaires
     (id, study_id, slug, title, description, schema_json,
      position, status, version, created_at, updated_at)
     VALUES (
       '00000000-0000-4000-8000-100000000020',
       '00000000-0000-4000-8000-100000000001',
       't2-post-game',
       'T2 — Post game',
       'Da compilare subito dopo la sessione di gioco.',
       '{"title":"Questionario T2 — Post-Game","description":"Hai appena finito di giocare. Questo questionario raccoglie le tue impressioni sull''esperienza.","showProgressBar":"top","progressBarType":"pages","showQuestionNumbers":"off","requiredText":"*","locale":"it","pages":[{"name":"codice_anonimo","title":"Codice Anonimo","description":"Inserisci le stesse risposte che hai dato nel questionario T1, cosi'' rigenererai lo stesso codice.","elements":[{"type":"text","name":"anon_madre","title":"Prima lettera del nome di tua madre","description":"Esempio: se tua madre si chiama Maria, scrivi M","isRequired":true,"maxLength":1,"inputType":"text","validators":[{"type":"regex","regexp":"^[a-zA-Z\\u00C0-\\u017F]$","text":"Inserisci una sola lettera dell''alfabeto"}]},{"type":"text","name":"anon_giorno","title":"Giorno del tuo compleanno (1-31)","description":"Solo il giorno. Esempio: se sei nato/a il 15 marzo, scrivi 15","isRequired":true,"inputType":"number","min":1,"max":31,"validators":[{"type":"regex","regexp":"^([1-9]|[12][0-9]|3[01])$","text":"Inserisci un numero da 1 a 31"}]},{"type":"text","name":"anon_nome","title":"Prima lettera del tuo nome","description":"Esempio: se ti chiami Vittorio, scrivi V","isRequired":true,"maxLength":1,"inputType":"text","validators":[{"type":"regex","regexp":"^[a-zA-Z\\u00C0-\\u017F]$","text":"Inserisci una sola lettera dell''alfabeto"}]},{"type":"text","name":"anon_telefono","title":"Prime due cifre del tuo numero di telefono","description":"Esempio: se il tuo numero inizia con 34..., scrivi 34","isRequired":true,"inputType":"number","min":0,"max":99,"validators":[{"type":"regex","regexp":"^[0-9]{1,2}$","text":"Inserisci due cifre (00-99)"}]}]},{"name":"mdmq","title":"Stile Decisionale","description":"Indica quanto ciascuna affermazione descrive il tuo modo abituale di prendere decisioni.","elements":[{"type":"matrix","name":"MDMQ","columns":[{"value":0,"text":"Non vero per me"},{"value":1,"text":"Abbastanza vero per me"},{"value":2,"text":"Vero per me"}],"rows":[{"value":"MDMQ_01","text":"Mi sento sotto un''enorme pressione di tempo quando prendo decisioni."},{"value":"MDMQ_02","text":"Mi piace prendere in considerazione tutte le alternative."},{"value":"MDMQ_03","text":"Preferisco lasciare le decisioni agli altri."},{"value":"MDMQ_04","text":"Cerco di individuare gli svantaggi di tutte le alternative."},{"value":"MDMQ_05","text":"Perdo molto tempo su questioni banali prima di arrivare alla decisione finale."},{"value":"MDMQ_06","text":"Considero quale sia il modo migliore per mettere in atto una decisione."},{"value":"MDMQ_07","text":"Anche dopo aver preso una decisione, rimando il momento di metterla in pratica."},{"value":"MDMQ_08","text":"Quando prendo decisioni mi piace raccogliere molte informazioni."},{"value":"MDMQ_09","text":"Evito di prendere decisioni."},{"value":"MDMQ_10","text":"Quando devo prendere una decisione, aspetto a lungo prima di iniziare a pensarci."},{"value":"MDMQ_11","text":"Non mi piace assumermi la responsabilita'' di prendere decisioni."},{"value":"MDMQ_12","text":"Cerco di avere chiari i miei obiettivi prima di scegliere."},{"value":"MDMQ_13","text":"La possibilita'' che un piccolo dettaglio possa andare storto mi fa cambiare improvvisamente preferenza."},{"value":"MDMQ_14","text":"Se una decisione puo'' essere presa da me o da un''altra persona, lascio che la prenda l''altra persona."},{"value":"MDMQ_15","text":"Quando affronto una decisione difficile mi sento pessimista riguardo alla possibilita'' di trovare una buona soluzione."},{"value":"MDMQ_16","text":"Faccio molta attenzione prima di scegliere."},{"value":"MDMQ_17","text":"Non prendo decisioni a meno che non sia davvero necessario."},{"value":"MDMQ_18","text":"Rimando le decisioni finche'' non e'' troppo tardi."},{"value":"MDMQ_19","text":"Preferisco che a decidere per me siano persone meglio informate."},{"value":"MDMQ_20","text":"Dopo aver preso una decisione, passo molto tempo a convincermi che fosse quella giusta."},{"value":"MDMQ_21","text":"Rimando il momento di prendere decisioni."},{"value":"MDMQ_22","text":"Non riesco a ragionare lucidamente se devo prendere una decisione in fretta."}]}]},{"name":"roci","title":"Gestione del Conflitto","description":"Pensa a come hai gestito situazioni di disaccordo durante il gioco e in generale con i tuoi colleghi.","elements":[{"type":"matrix","name":"ROCI","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Indeciso"},{"value":4,"text":"D''accordo"},{"value":5,"text":"Fortemente d''accordo"}],"rows":[{"value":"ROCI_01","text":"Cerco di esaminare a fondo un problema con il mio collega per trovare una soluzione accettabile per entrambi."},{"value":"ROCI_02","text":"In generale cerco di soddisfare i bisogni del mio collega."},{"value":"ROCI_03","text":"Cerco di evitare di essere messo in difficolta'' e tengo per me il conflitto con il mio collega."},{"value":"ROCI_04","text":"Cerco di integrare le mie idee con quelle del mio collega per arrivare a una decisione congiunta."},{"value":"ROCI_05","text":"Do qualcosa per ottenere qualcosa in cambio."},{"value":"ROCI_06","text":"Cerco di lavorare con il mio collega per trovare soluzioni che soddisfino le aspettative di entrambi."},{"value":"ROCI_07","text":"Di solito evito discussioni aperte sulle mie divergenze con il mio collega."},{"value":"ROCI_08","text":"Di solito resto fermo sulla mia soluzione a un problema."},{"value":"ROCI_09","text":"Cerco di trovare una via di mezzo per risolvere un''impasse."},{"value":"ROCI_10","text":"Uso la mia influenza per far accettare le mie idee."},{"value":"ROCI_11","text":"Uso la mia autorita'' per prendere una decisione a mio favore."},{"value":"ROCI_12","text":"Di solito cerco di andare incontro ai desideri del mio collega."},{"value":"ROCI_13","text":"Cedo di fronte ai desideri del mio collega."},{"value":"ROCI_14","text":"A volte vinco e a volte perdo."},{"value":"ROCI_15","text":"Scambio informazioni accurate con il mio collega per risolvere un problema insieme."},{"value":"ROCI_16","text":"A volte aiuto il mio collega a prendere una decisione a suo favore."},{"value":"ROCI_17","text":"Di solito faccio concessioni al mio collega."},{"value":"ROCI_18","text":"Argomento il mio caso con il collega per mostrare i meriti della mia posizione."},{"value":"ROCI_19","text":"Cerco di minimizzare le nostre differenze per raggiungere un compromesso."},{"value":"ROCI_20","text":"Di solito propongo una soluzione intermedia per sbloccare una situazione."},{"value":"ROCI_21","text":"Negozio con il mio collega in modo da raggiungere un compromesso."},{"value":"ROCI_22","text":"Cerco di stare lontano dai disaccordi con il mio collega."},{"value":"ROCI_23","text":"Evito un confronto con il mio collega."},{"value":"ROCI_24","text":"Uso la mia competenza per prendere una decisione a mio favore."},{"value":"ROCI_25","text":"Spesso assecondo i suggerimenti del mio collega."},{"value":"ROCI_26","text":"Uso il dare e avere in modo da raggiungere un compromesso."},{"value":"ROCI_27","text":"Sono generalmente fermo nel perseguire la mia posizione."},{"value":"ROCI_28","text":"Cerco di portare alla luce tutte le nostre preoccupazioni affinche'' le questioni possano essere risolte nel modo migliore."}]}]},{"name":"svo","title":"Orientamento Sociale","description":"Leggi attentamente le istruzioni prima di rispondere.","elements":[{"type":"html","name":"svo_intro","html":"<div style=''background:#FFFFFF;padding:18px 22px;border-radius:10px;margin:4px 0 16px;box-shadow:0 1px 4px rgba(0,0,0,.06);''><p style=''margin:0 0 10px;color:#1b2528;font-weight:600;''>Immagina di essere stato/a accoppiato/a casualmente con <u>un''altra persona</u> che non conosci e che non incontrerai mai.</p><p style=''margin:0 0 10px;color:#657179;font-size:.95em;line-height:1.5;''>L''altra persona non sa chi sei, come tu non sai chi sia. Anche le vostre scelte resteranno reciprocamente anonime.</p><p style=''margin:0 0 10px;color:#657179;font-size:.95em;line-height:1.5;''>Ti presenteremo 6 scelte. In ciascuna dovrai decidere come distribuire dei punti (che valgono soldi) tra te stesso/a e l''altra persona. Ogni punto ha lo stesso valore per te e per l''altra persona.</p><p style=''margin:0;color:#657179;font-size:.95em;line-height:1.5;''>Per ciascuna scelta vedrai 9 combinazioni possibili. La riga sopra indica quanti punti riceveresti tu; quella sotto quanti ne riceverebbe l''altra persona. <strong>Clicca sulla combinazione che preferisci.</strong></p></div>"},{"type":"html","name":"svo_widget","html":"<div id=''svoContainer''></div>"}]},{"name":"tps","title":"Sicurezza Psicologica nel Team","description":"Pensa al team con cui hai appena giocato. Indica il tuo grado di accordo con ciascuna affermazione.","elements":[{"type":"matrix","name":"TPS","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Leggermente in disaccordo"},{"value":4,"text":"Neutrale"},{"value":5,"text":"Leggermente d''accordo"},{"value":6,"text":"D''accordo"},{"value":7,"text":"Fortemente d''accordo"}],"rows":[{"value":"TPS_01","text":"Se commetti un errore in questo team, viene usato contro di te."},{"value":"TPS_02","text":"I membri di questo team sono in grado di sollevare problemi e questioni difficili."},{"value":"TPS_03","text":"Le persone in questo team a volte rifiutano gli altri perche'' sono diversi."},{"value":"TPS_04","text":"E'' sicuro correre rischi in questo team."},{"value":"TPS_05","text":"E'' difficile chiedere aiuto agli altri membri di questo team."},{"value":"TPS_06","text":"Nessuno in questo team saboterebbe deliberatamente il mio lavoro."},{"value":"TPS_07","text":"Le mie competenze e i miei talenti unici sono apprezzati e utilizzati in questo team."}]}]},{"name":"tci","title":"Clima di Team","description":"Pensa al team con cui hai appena giocato. Indica il tuo grado di accordo con le seguenti affermazioni.","elements":[{"type":"matrix","name":"TCI","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Indeciso"},{"value":4,"text":"D''accordo"},{"value":5,"text":"Fortemente d''accordo"}],"rows":[{"value":"TCI_01","text":"In che misura sei d''accordo con gli obiettivi del tuo team?"},{"value":"TCI_02","text":"In che misura ritieni che gli obiettivi del team siano compresi chiaramente dagli altri membri?"},{"value":"TCI_03","text":"In che misura ritieni che gli obiettivi del team siano effettivamente raggiungibili?"},{"value":"TCI_04","text":"Quanto ritieni che questi obiettivi siano importanti per l''organizzazione?"},{"value":"TCI_05","text":"Abbiamo un atteggiamento del tipo ''siamo tutti nella stessa barca''."},{"value":"TCI_06","text":"Le persone si tengono reciprocamente informate sulle questioni lavorative nel team."},{"value":"TCI_07","text":"Le persone si sentono comprese e accettate reciprocamente."},{"value":"TCI_08","text":"Ci sono tentativi concreti di condividere le informazioni in tutto il team."},{"value":"TCI_09","text":"I membri del team sono pronti a mettere in discussione le basi di cio'' che il team sta facendo?"},{"value":"TCI_10","text":"Il team valuta criticamente i potenziali punti deboli di cio'' che sta facendo?"},{"value":"TCI_11","text":"I membri del team costruiscono sulle idee degli altri per ottenere i migliori risultati?"},{"value":"TCI_12","text":"Le persone in questo team sono sempre alla ricerca di modi nuovi e originali per affrontare i problemi."},{"value":"TCI_13","text":"In questo team ci prendiamo il tempo necessario per sviluppare nuove idee."},{"value":"TCI_14","text":"Le persone nel team cooperano per contribuire a sviluppare e applicare nuove idee."}]}]},{"name":"secom","title":"Autoefficacia Comunicativa","description":"Pensa alle tue capacita'' di comunicazione nel lavoro di squadra.","elements":[{"type":"matrix","name":"SECOM","columns":[{"value":1,"text":"Per niente sicuro/a"},{"value":2,"text":"2"},{"value":3,"text":"3"},{"value":4,"text":"4"},{"value":5,"text":"5"},{"value":6,"text":"6"},{"value":7,"text":"Completamente sicuro/a"}],"rows":[{"value":"SECOM_01","text":"Sono in grado di esprimere le mie idee in modo chiaro durante una discussione di gruppo."},{"value":"SECOM_02","text":"Sono in grado di ascoltare attivamente i miei colleghi e cogliere i punti chiave del loro ragionamento."},{"value":"SECOM_03","text":"Sono in grado di gestire un disaccordo con un collega senza compromettere la relazione."},{"value":"SECOM_04","text":"Sono in grado di coordinare le attivita'' del mio team comunicando in modo efficace."}]}]},{"name":"fss","title":"Esperienza di Flow","description":"Pensa all''esperienza di gioco che hai appena vissuto. Indica il tuo grado di accordo con ciascuna affermazione.","elements":[{"type":"matrix","name":"FSS","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Leggermente in disaccordo"},{"value":4,"text":"Neutrale"},{"value":5,"text":"Leggermente d''accordo"},{"value":6,"text":"D''accordo"},{"value":7,"text":"Fortemente d''accordo"}],"rows":[{"value":"FSS_01","text":"Mi sentivo stimolato/a nella giusta misura."},{"value":"FSS_02","text":"I miei pensieri e le mie azioni procedevano in modo fluido e scorrevole."},{"value":"FSS_03","text":"Non mi rendevo conto del tempo che passava."},{"value":"FSS_04","text":"Non avevo difficolta'' a concentrarmi."},{"value":"FSS_05","text":"La mia mente era completamente lucida."},{"value":"FSS_06","text":"Ero totalmente assorbito/a da quello che stavo facendo."},{"value":"FSS_07","text":"I pensieri e i movimenti giusti arrivavano da soli."},{"value":"FSS_08","text":"Sapevo cosa dovevo fare ad ogni passaggio."},{"value":"FSS_09","text":"Sentivo di avere tutto sotto controllo."},{"value":"FSS_10","text":"Ero completamente perso/a nei miei pensieri."},{"value":"FSS_11","text":"C''era qualcosa di importante in gioco per me."},{"value":"FSS_12","text":"Non dovevo fare errori."},{"value":"FSS_13","text":"Ero preoccupato/a di fallire."}]}]},{"name":"reaction","title":"Valutazione dell''Attivita''","description":"Rispondi alle seguenti domande sull''attivita'' di team building a cui hai appena partecipato.","elements":[{"type":"matrix","name":"REACT","columns":[{"value":1,"text":"Per niente d''accordo"},{"value":2,"text":"2"},{"value":3,"text":"3"},{"value":4,"text":"4"},{"value":5,"text":"5"},{"value":6,"text":"6"},{"value":7,"text":"Completamente d''accordo"}],"rows":[{"value":"REACT_01","text":"L''attivita'' e'' stata coinvolgente."},{"value":"REACT_02","text":"Ho trovato l''attivita'' utile per il mio sviluppo professionale."},{"value":"REACT_03","text":"L''attivita'' mi ha fatto riflettere sul mio modo di prendere decisioni."},{"value":"REACT_04","text":"L''attivita'' mi ha fatto riflettere sul mio modo di gestire i conflitti."},{"value":"REACT_05","text":"L''attivita'' ha migliorato la mia percezione del team."},{"value":"REACT_06","text":"Consiglierei questa attivita'' ad altri colleghi."},{"value":"REACT_07","text":"Parteciperei di nuovo a un''attivita'' simile."},{"value":"REACT_08","text":"L''attivita'' e'' stata piu'' efficace di altre attivita'' di team building a cui ho partecipato."}]}]},{"name":"open","title":"Riflessioni","description":"Rispondi liberamente alle seguenti domande.","elements":[{"type":"comment","name":"OPEN_01","title":"Quale momento del gioco ti ha fatto piu'' riflettere sul tuo modo di agire?","rows":4},{"type":"comment","name":"OPEN_02","title":"Hai notato qualcosa di nuovo sul tuo stile decisionale o sul tuo modo di gestire i conflitti?","rows":4},{"type":"comment","name":"OPEN_03","title":"C''e'' qualcosa che faresti diversamente nella prossima partita?","rows":4}]}]}',
       1,
       'active',
       1,
       unixepoch()*1000,
       unixepoch()*1000
     );

INSERT OR REPLACE INTO research_questionnaires
     (id, study_id, slug, title, description, schema_json,
      position, status, version, created_at, updated_at)
     VALUES (
       '00000000-0000-4000-8000-100000000030',
       '00000000-0000-4000-8000-100000000001',
       't3-followup-2w',
       'T3 — Follow-up 2 settimane',
       'Follow-up a due settimane dalla sessione.',
       '{"title":"Questionario T3 — Follow-up (2 settimane)","description":"Sono passate circa 2 settimane dall''attivita''. Questo breve questionario ci aiuta a capire se ci sono stati dei cambiamenti.","showProgressBar":"top","progressBarType":"pages","showQuestionNumbers":"off","requiredText":"*","locale":"it","pages":[{"name":"codice_anonimo","title":"Codice Anonimo","description":"Inserisci le stesse risposte che hai dato nel questionario T1, T2, cosi'' rigenererai lo stesso codice.","elements":[{"type":"text","name":"anon_madre","title":"Prima lettera del nome di tua madre","description":"Esempio: se tua madre si chiama Maria, scrivi M","isRequired":true,"maxLength":1,"inputType":"text","validators":[{"type":"regex","regexp":"^[a-zA-Z\\u00C0-\\u017F]$","text":"Inserisci una sola lettera dell''alfabeto"}]},{"type":"text","name":"anon_giorno","title":"Giorno del tuo compleanno (1-31)","description":"Solo il giorno. Esempio: se sei nato/a il 15 marzo, scrivi 15","isRequired":true,"inputType":"number","min":1,"max":31,"validators":[{"type":"regex","regexp":"^([1-9]|[12][0-9]|3[01])$","text":"Inserisci un numero da 1 a 31"}]},{"type":"text","name":"anon_nome","title":"Prima lettera del tuo nome","description":"Esempio: se ti chiami Vittorio, scrivi V","isRequired":true,"maxLength":1,"inputType":"text","validators":[{"type":"regex","regexp":"^[a-zA-Z\\u00C0-\\u017F]$","text":"Inserisci una sola lettera dell''alfabeto"}]},{"type":"text","name":"anon_telefono","title":"Prime due cifre del tuo numero di telefono","description":"Esempio: se il tuo numero inizia con 34..., scrivi 34","isRequired":true,"inputType":"number","min":0,"max":99,"validators":[{"type":"regex","regexp":"^[0-9]{1,2}$","text":"Inserisci due cifre (00-99)"}]}]},{"name":"mdmq","title":"Stile Decisionale","description":"Indica quanto ciascuna affermazione descrive il tuo modo abituale di prendere decisioni.","elements":[{"type":"matrix","name":"MDMQ","columns":[{"value":0,"text":"Non vero per me"},{"value":1,"text":"Abbastanza vero per me"},{"value":2,"text":"Vero per me"}],"rows":[{"value":"MDMQ_01","text":"Mi sento sotto un''enorme pressione di tempo quando prendo decisioni."},{"value":"MDMQ_02","text":"Mi piace prendere in considerazione tutte le alternative."},{"value":"MDMQ_03","text":"Preferisco lasciare le decisioni agli altri."},{"value":"MDMQ_04","text":"Cerco di individuare gli svantaggi di tutte le alternative."},{"value":"MDMQ_05","text":"Perdo molto tempo su questioni banali prima di arrivare alla decisione finale."},{"value":"MDMQ_06","text":"Considero quale sia il modo migliore per mettere in atto una decisione."},{"value":"MDMQ_07","text":"Anche dopo aver preso una decisione, rimando il momento di metterla in pratica."},{"value":"MDMQ_08","text":"Quando prendo decisioni mi piace raccogliere molte informazioni."},{"value":"MDMQ_09","text":"Evito di prendere decisioni."},{"value":"MDMQ_10","text":"Quando devo prendere una decisione, aspetto a lungo prima di iniziare a pensarci."},{"value":"MDMQ_11","text":"Non mi piace assumermi la responsabilita'' di prendere decisioni."},{"value":"MDMQ_12","text":"Cerco di avere chiari i miei obiettivi prima di scegliere."},{"value":"MDMQ_13","text":"La possibilita'' che un piccolo dettaglio possa andare storto mi fa cambiare improvvisamente preferenza."},{"value":"MDMQ_14","text":"Se una decisione puo'' essere presa da me o da un''altra persona, lascio che la prenda l''altra persona."},{"value":"MDMQ_15","text":"Quando affronto una decisione difficile mi sento pessimista riguardo alla possibilita'' di trovare una buona soluzione."},{"value":"MDMQ_16","text":"Faccio molta attenzione prima di scegliere."},{"value":"MDMQ_17","text":"Non prendo decisioni a meno che non sia davvero necessario."},{"value":"MDMQ_18","text":"Rimando le decisioni finche'' non e'' troppo tardi."},{"value":"MDMQ_19","text":"Preferisco che a decidere per me siano persone meglio informate."},{"value":"MDMQ_20","text":"Dopo aver preso una decisione, passo molto tempo a convincermi che fosse quella giusta."},{"value":"MDMQ_21","text":"Rimando il momento di prendere decisioni."},{"value":"MDMQ_22","text":"Non riesco a ragionare lucidamente se devo prendere una decisione in fretta."}]}]},{"name":"roci","title":"Gestione del Conflitto","description":"Pensa a come gestisci le situazioni di disaccordo con i tuoi colleghi.","elements":[{"type":"matrix","name":"ROCI","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Indeciso"},{"value":4,"text":"D''accordo"},{"value":5,"text":"Fortemente d''accordo"}],"rows":[{"value":"ROCI_01","text":"Cerco di esaminare a fondo un problema con il mio collega per trovare una soluzione accettabile per entrambi."},{"value":"ROCI_02","text":"In generale cerco di soddisfare i bisogni del mio collega."},{"value":"ROCI_03","text":"Cerco di evitare di essere messo in difficolta'' e tengo per me il conflitto con il mio collega."},{"value":"ROCI_04","text":"Cerco di integrare le mie idee con quelle del mio collega per arrivare a una decisione congiunta."},{"value":"ROCI_05","text":"Do qualcosa per ottenere qualcosa in cambio."},{"value":"ROCI_06","text":"Cerco di lavorare con il mio collega per trovare soluzioni che soddisfino le aspettative di entrambi."},{"value":"ROCI_07","text":"Di solito evito discussioni aperte sulle mie divergenze con il mio collega."},{"value":"ROCI_08","text":"Di solito resto fermo sulla mia soluzione a un problema."},{"value":"ROCI_09","text":"Cerco di trovare una via di mezzo per risolvere un''impasse."},{"value":"ROCI_10","text":"Uso la mia influenza per far accettare le mie idee."},{"value":"ROCI_11","text":"Uso la mia autorita'' per prendere una decisione a mio favore."},{"value":"ROCI_12","text":"Di solito cerco di andare incontro ai desideri del mio collega."},{"value":"ROCI_13","text":"Cedo di fronte ai desideri del mio collega."},{"value":"ROCI_14","text":"A volte vinco e a volte perdo."},{"value":"ROCI_15","text":"Scambio informazioni accurate con il mio collega per risolvere un problema insieme."},{"value":"ROCI_16","text":"A volte aiuto il mio collega a prendere una decisione a suo favore."},{"value":"ROCI_17","text":"Di solito faccio concessioni al mio collega."},{"value":"ROCI_18","text":"Argomento il mio caso con il collega per mostrare i meriti della mia posizione."},{"value":"ROCI_19","text":"Cerco di minimizzare le nostre differenze per raggiungere un compromesso."},{"value":"ROCI_20","text":"Di solito propongo una soluzione intermedia per sbloccare una situazione."},{"value":"ROCI_21","text":"Negozio con il mio collega in modo da raggiungere un compromesso."},{"value":"ROCI_22","text":"Cerco di stare lontano dai disaccordi con il mio collega."},{"value":"ROCI_23","text":"Evito un confronto con il mio collega."},{"value":"ROCI_24","text":"Uso la mia competenza per prendere una decisione a mio favore."},{"value":"ROCI_25","text":"Spesso assecondo i suggerimenti del mio collega."},{"value":"ROCI_26","text":"Uso il dare e avere in modo da raggiungere un compromesso."},{"value":"ROCI_27","text":"Sono generalmente fermo nel perseguire la mia posizione."},{"value":"ROCI_28","text":"Cerco di portare alla luce tutte le nostre preoccupazioni affinche'' le questioni possano essere risolte nel modo migliore."}]}]},{"name":"tps","title":"Sicurezza Psicologica nel Team","description":"Pensa al team con cui lavori. Indica il tuo grado di accordo con ciascuna affermazione.","elements":[{"type":"matrix","name":"TPS","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Leggermente in disaccordo"},{"value":4,"text":"Neutrale"},{"value":5,"text":"Leggermente d''accordo"},{"value":6,"text":"D''accordo"},{"value":7,"text":"Fortemente d''accordo"}],"rows":[{"value":"TPS_01","text":"Se commetti un errore in questo team, viene usato contro di te."},{"value":"TPS_02","text":"I membri di questo team sono in grado di sollevare problemi e questioni difficili."},{"value":"TPS_03","text":"Le persone in questo team a volte rifiutano gli altri perche'' sono diversi."},{"value":"TPS_04","text":"E'' sicuro correre rischi in questo team."},{"value":"TPS_05","text":"E'' difficile chiedere aiuto agli altri membri di questo team."},{"value":"TPS_06","text":"Nessuno in questo team saboterebbe deliberatamente il mio lavoro."},{"value":"TPS_07","text":"Le mie competenze e i miei talenti unici sono apprezzati e utilizzati in questo team."}]}]},{"name":"tci","title":"Clima di Team","description":"Pensa al team con cui lavori. Indica il tuo grado di accordo con le seguenti affermazioni.","elements":[{"type":"matrix","name":"TCI","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Indeciso"},{"value":4,"text":"D''accordo"},{"value":5,"text":"Fortemente d''accordo"}],"rows":[{"value":"TCI_01","text":"In che misura sei d''accordo con gli obiettivi del tuo team?"},{"value":"TCI_02","text":"In che misura ritieni che gli obiettivi del team siano compresi chiaramente dagli altri membri?"},{"value":"TCI_03","text":"In che misura ritieni che gli obiettivi del team siano effettivamente raggiungibili?"},{"value":"TCI_04","text":"Quanto ritieni che questi obiettivi siano importanti per l''organizzazione?"},{"value":"TCI_05","text":"Abbiamo un atteggiamento del tipo ''siamo tutti nella stessa barca''."},{"value":"TCI_06","text":"Le persone si tengono reciprocamente informate sulle questioni lavorative nel team."},{"value":"TCI_07","text":"Le persone si sentono comprese e accettate reciprocamente."},{"value":"TCI_08","text":"Ci sono tentativi concreti di condividere le informazioni in tutto il team."},{"value":"TCI_09","text":"I membri del team sono pronti a mettere in discussione le basi di cio'' che il team sta facendo?"},{"value":"TCI_10","text":"Il team valuta criticamente i potenziali punti deboli di cio'' che sta facendo?"},{"value":"TCI_11","text":"I membri del team costruiscono sulle idee degli altri per ottenere i migliori risultati?"},{"value":"TCI_12","text":"Le persone in questo team sono sempre alla ricerca di modi nuovi e originali per affrontare i problemi."},{"value":"TCI_13","text":"In questo team ci prendiamo il tempo necessario per sviluppare nuove idee."},{"value":"TCI_14","text":"Le persone nel team cooperano per contribuire a sviluppare e applicare nuove idee."}]}]},{"name":"secom","title":"Autoefficacia Comunicativa","description":"Pensa alle tue capacita'' di comunicazione nel lavoro di squadra.","elements":[{"type":"matrix","name":"SECOM","columns":[{"value":1,"text":"Per niente sicuro/a"},{"value":2,"text":"2"},{"value":3,"text":"3"},{"value":4,"text":"4"},{"value":5,"text":"5"},{"value":6,"text":"6"},{"value":7,"text":"Completamente sicuro/a"}],"rows":[{"value":"SECOM_01","text":"Sono in grado di esprimere le mie idee in modo chiaro durante una discussione di gruppo."},{"value":"SECOM_02","text":"Sono in grado di ascoltare attivamente i miei colleghi e cogliere i punti chiave del loro ragionamento."},{"value":"SECOM_03","text":"Sono in grado di gestire un disaccordo con un collega senza compromettere la relazione."},{"value":"SECOM_04","text":"Sono in grado di coordinare le attivita'' del mio team comunicando in modo efficace."}]}]}]}',
