     );

INSERT OR REPLACE INTO research_questionnaires
     (id, study_id, slug, title, description, schema_json,
      position, status, version, created_at, updated_at)
     VALUES (
       '00000000-0000-4000-8000-100000000040',
       '00000000-0000-4000-8000-100000000001',
       't4-followup-1m',
       'T4 — Follow-up 1 mese',
       'Follow-up a un mese dalla sessione.',
       '{"title":"Questionario T4 — Follow-up (1 mese)","description":"E'' passato circa un mese dall''attivita''. Questo e'' l''ultimo questionario della ricerca. Grazie per la tua partecipazione!","showProgressBar":"top","progressBarType":"pages","showQuestionNumbers":"off","requiredText":"*","locale":"it","pages":[{"name":"codice_anonimo","title":"Codice Anonimo","description":"Inserisci le stesse risposte che hai dato nel questionario T1, T2, T3, cosi'' rigenererai lo stesso codice.","elements":[{"type":"text","name":"anon_madre","title":"Prima lettera del nome di tua madre","description":"Esempio: se tua madre si chiama Maria, scrivi M","isRequired":true,"maxLength":1,"inputType":"text","validators":[{"type":"regex","regexp":"^[a-zA-Z\\u00C0-\\u017F]$","text":"Inserisci una sola lettera dell''alfabeto"}]},{"type":"text","name":"anon_giorno","title":"Giorno del tuo compleanno (1-31)","description":"Solo il giorno. Esempio: se sei nato/a il 15 marzo, scrivi 15","isRequired":true,"inputType":"number","min":1,"max":31,"validators":[{"type":"regex","regexp":"^([1-9]|[12][0-9]|3[01])$","text":"Inserisci un numero da 1 a 31"}]},{"type":"text","name":"anon_nome","title":"Prima lettera del tuo nome","description":"Esempio: se ti chiami Vittorio, scrivi V","isRequired":true,"maxLength":1,"inputType":"text","validators":[{"type":"regex","regexp":"^[a-zA-Z\\u00C0-\\u017F]$","text":"Inserisci una sola lettera dell''alfabeto"}]},{"type":"text","name":"anon_telefono","title":"Prime due cifre del tuo numero di telefono","description":"Esempio: se il tuo numero inizia con 34..., scrivi 34","isRequired":true,"inputType":"number","min":0,"max":99,"validators":[{"type":"regex","regexp":"^[0-9]{1,2}$","text":"Inserisci due cifre (00-99)"}]}]},{"name":"mdmq","title":"Stile Decisionale","description":"Indica quanto ciascuna affermazione descrive il tuo modo abituale di prendere decisioni.","elements":[{"type":"matrix","name":"MDMQ","columns":[{"value":0,"text":"Non vero per me"},{"value":1,"text":"Abbastanza vero per me"},{"value":2,"text":"Vero per me"}],"rows":[{"value":"MDMQ_01","text":"Mi sento sotto un''enorme pressione di tempo quando prendo decisioni."},{"value":"MDMQ_02","text":"Mi piace prendere in considerazione tutte le alternative."},{"value":"MDMQ_03","text":"Preferisco lasciare le decisioni agli altri."},{"value":"MDMQ_04","text":"Cerco di individuare gli svantaggi di tutte le alternative."},{"value":"MDMQ_05","text":"Perdo molto tempo su questioni banali prima di arrivare alla decisione finale."},{"value":"MDMQ_06","text":"Considero quale sia il modo migliore per mettere in atto una decisione."},{"value":"MDMQ_07","text":"Anche dopo aver preso una decisione, rimando il momento di metterla in pratica."},{"value":"MDMQ_08","text":"Quando prendo decisioni mi piace raccogliere molte informazioni."},{"value":"MDMQ_09","text":"Evito di prendere decisioni."},{"value":"MDMQ_10","text":"Quando devo prendere una decisione, aspetto a lungo prima di iniziare a pensarci."},{"value":"MDMQ_11","text":"Non mi piace assumermi la responsabilita'' di prendere decisioni."},{"value":"MDMQ_12","text":"Cerco di avere chiari i miei obiettivi prima di scegliere."},{"value":"MDMQ_13","text":"La possibilita'' che un piccolo dettaglio possa andare storto mi fa cambiare improvvisamente preferenza."},{"value":"MDMQ_14","text":"Se una decisione puo'' essere presa da me o da un''altra persona, lascio che la prenda l''altra persona."},{"value":"MDMQ_15","text":"Quando affronto una decisione difficile mi sento pessimista riguardo alla possibilita'' di trovare una buona soluzione."},{"value":"MDMQ_16","text":"Faccio molta attenzione prima di scegliere."},{"value":"MDMQ_17","text":"Non prendo decisioni a meno che non sia davvero necessario."},{"value":"MDMQ_18","text":"Rimando le decisioni finche'' non e'' troppo tardi."},{"value":"MDMQ_19","text":"Preferisco che a decidere per me siano persone meglio informate."},{"value":"MDMQ_20","text":"Dopo aver preso una decisione, passo molto tempo a convincermi che fosse quella giusta."},{"value":"MDMQ_21","text":"Rimando il momento di prendere decisioni."},{"value":"MDMQ_22","text":"Non riesco a ragionare lucidamente se devo prendere una decisione in fretta."}]}]},{"name":"roci","title":"Gestione del Conflitto","description":"Pensa a come gestisci le situazioni di disaccordo con i tuoi colleghi.","elements":[{"type":"matrix","name":"ROCI","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Indeciso"},{"value":4,"text":"D''accordo"},{"value":5,"text":"Fortemente d''accordo"}],"rows":[{"value":"ROCI_01","text":"Cerco di esaminare a fondo un problema con il mio collega per trovare una soluzione accettabile per entrambi."},{"value":"ROCI_02","text":"In generale cerco di soddisfare i bisogni del mio collega."},{"value":"ROCI_03","text":"Cerco di evitare di essere messo in difficolta'' e tengo per me il conflitto con il mio collega."},{"value":"ROCI_04","text":"Cerco di integrare le mie idee con quelle del mio collega per arrivare a una decisione congiunta."},{"value":"ROCI_05","text":"Do qualcosa per ottenere qualcosa in cambio."},{"value":"ROCI_06","text":"Cerco di lavorare con il mio collega per trovare soluzioni che soddisfino le aspettative di entrambi."},{"value":"ROCI_07","text":"Di solito evito discussioni aperte sulle mie divergenze con il mio collega."},{"value":"ROCI_08","text":"Di solito resto fermo sulla mia soluzione a un problema."},{"value":"ROCI_09","text":"Cerco di trovare una via di mezzo per risolvere un''impasse."},{"value":"ROCI_10","text":"Uso la mia influenza per far accettare le mie idee."},{"value":"ROCI_11","text":"Uso la mia autorita'' per prendere una decisione a mio favore."},{"value":"ROCI_12","text":"Di solito cerco di andare incontro ai desideri del mio collega."},{"value":"ROCI_13","text":"Cedo di fronte ai desideri del mio collega."},{"value":"ROCI_14","text":"A volte vinco e a volte perdo."},{"value":"ROCI_15","text":"Scambio informazioni accurate con il mio collega per risolvere un problema insieme."},{"value":"ROCI_16","text":"A volte aiuto il mio collega a prendere una decisione a suo favore."},{"value":"ROCI_17","text":"Di solito faccio concessioni al mio collega."},{"value":"ROCI_18","text":"Argomento il mio caso con il collega per mostrare i meriti della mia posizione."},{"value":"ROCI_19","text":"Cerco di minimizzare le nostre differenze per raggiungere un compromesso."},{"value":"ROCI_20","text":"Di solito propongo una soluzione intermedia per sbloccare una situazione."},{"value":"ROCI_21","text":"Negozio con il mio collega in modo da raggiungere un compromesso."},{"value":"ROCI_22","text":"Cerco di stare lontano dai disaccordi con il mio collega."},{"value":"ROCI_23","text":"Evito un confronto con il mio collega."},{"value":"ROCI_24","text":"Uso la mia competenza per prendere una decisione a mio favore."},{"value":"ROCI_25","text":"Spesso assecondo i suggerimenti del mio collega."},{"value":"ROCI_26","text":"Uso il dare e avere in modo da raggiungere un compromesso."},{"value":"ROCI_27","text":"Sono generalmente fermo nel perseguire la mia posizione."},{"value":"ROCI_28","text":"Cerco di portare alla luce tutte le nostre preoccupazioni affinche'' le questioni possano essere risolte nel modo migliore."}]}]},{"name":"tps","title":"Sicurezza Psicologica nel Team","description":"Pensa al team con cui lavori. Indica il tuo grado di accordo con ciascuna affermazione.","elements":[{"type":"matrix","name":"TPS","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Leggermente in disaccordo"},{"value":4,"text":"Neutrale"},{"value":5,"text":"Leggermente d''accordo"},{"value":6,"text":"D''accordo"},{"value":7,"text":"Fortemente d''accordo"}],"rows":[{"value":"TPS_01","text":"Se commetti un errore in questo team, viene usato contro di te."},{"value":"TPS_02","text":"I membri di questo team sono in grado di sollevare problemi e questioni difficili."},{"value":"TPS_03","text":"Le persone in questo team a volte rifiutano gli altri perche'' sono diversi."},{"value":"TPS_04","text":"E'' sicuro correre rischi in questo team."},{"value":"TPS_05","text":"E'' difficile chiedere aiuto agli altri membri di questo team."},{"value":"TPS_06","text":"Nessuno in questo team saboterebbe deliberatamente il mio lavoro."},{"value":"TPS_07","text":"Le mie competenze e i miei talenti unici sono apprezzati e utilizzati in questo team."}]}]},{"name":"tci","title":"Clima di Team","description":"Pensa al team con cui lavori. Indica il tuo grado di accordo con le seguenti affermazioni.","elements":[{"type":"matrix","name":"TCI","columns":[{"value":1,"text":"Fortemente in disaccordo"},{"value":2,"text":"In disaccordo"},{"value":3,"text":"Indeciso"},{"value":4,"text":"D''accordo"},{"value":5,"text":"Fortemente d''accordo"}],"rows":[{"value":"TCI_01","text":"In che misura sei d''accordo con gli obiettivi del tuo team?"},{"value":"TCI_02","text":"In che misura ritieni che gli obiettivi del team siano compresi chiaramente dagli altri membri?"},{"value":"TCI_03","text":"In che misura ritieni che gli obiettivi del team siano effettivamente raggiungibili?"},{"value":"TCI_04","text":"Quanto ritieni che questi obiettivi siano importanti per l''organizzazione?"},{"value":"TCI_05","text":"Abbiamo un atteggiamento del tipo ''siamo tutti nella stessa barca''."},{"value":"TCI_06","text":"Le persone si tengono reciprocamente informate sulle questioni lavorative nel team."},{"value":"TCI_07","text":"Le persone si sentono comprese e accettate reciprocamente."},{"value":"TCI_08","text":"Ci sono tentativi concreti di condividere le informazioni in tutto il team."},{"value":"TCI_09","text":"I membri del team sono pronti a mettere in discussione le basi di cio'' che il team sta facendo?"},{"value":"TCI_10","text":"Il team valuta criticamente i potenziali punti deboli di cio'' che sta facendo?"},{"value":"TCI_11","text":"I membri del team costruiscono sulle idee degli altri per ottenere i migliori risultati?"},{"value":"TCI_12","text":"Le persone in questo team sono sempre alla ricerca di modi nuovi e originali per affrontare i problemi."},{"value":"TCI_13","text":"In questo team ci prendiamo il tempo necessario per sviluppare nuove idee."},{"value":"TCI_14","text":"Le persone nel team cooperano per contribuire a sviluppare e applicare nuove idee."}]}]},{"name":"secom","title":"Autoefficacia Comunicativa","description":"Pensa alle tue capacita'' di comunicazione nel lavoro di squadra.","elements":[{"type":"matrix","name":"SECOM","columns":[{"value":1,"text":"Per niente sicuro/a"},{"value":2,"text":"2"},{"value":3,"text":"3"},{"value":4,"text":"4"},{"value":5,"text":"5"},{"value":6,"text":"6"},{"value":7,"text":"Completamente sicuro/a"}],"rows":[{"value":"SECOM_01","text":"Sono in grado di esprimere le mie idee in modo chiaro durante una discussione di gruppo."},{"value":"SECOM_02","text":"Sono in grado di ascoltare attivamente i miei colleghi e cogliere i punti chiave del loro ragionamento."},{"value":"SECOM_03","text":"Sono in grado di gestire un disaccordo con un collega senza compromettere la relazione."},{"value":"SECOM_04","text":"Sono in grado di coordinare le attivita'' del mio team comunicando in modo efficace."}]}]}]}',
